    fn into_deserializer_error_cpp_type(&self, expected_ty: Option<&syn::Type>) -> Option<String> {
        if self.is_type_param_in_scope("E") {
            return Some("E".to_string());
        }
        let err_ty = self.expected_result_type_arg(expected_ty, 1).or_else(|| {
            self.current_return_type_hint()
                .and_then(|ret| self.expected_result_type_arg(Some(ret), 1))
        })?;
        let err_cpp = self.map_type(err_ty);
        if err_cpp == "auto"
            || err_cpp.contains("/* TODO")
            || type_string_has_auto_placeholder(&err_cpp)
        {
            return None;
        }
        Some(err_cpp)
    }

    fn strip_cpp_cvref_qualifiers(mut ty: String) -> String {
        loop {
            let trimmed = ty.trim().to_string();
            if let Some(stripped) = trimmed.strip_prefix("const ") {
                ty = stripped.trim().to_string();
                continue;
            }
            if let Some(stripped) = trimmed.strip_prefix("volatile ") {
                ty = stripped.trim().to_string();
                continue;
            }
            ty = trimmed;
            break;
        }
        while ty.ends_with('&') {
            ty.pop();
            ty = ty.trim_end().to_string();
        }
        ty
    }

    fn builtin_deserializer_owner_for_cpp_type(&self, cpp_ty: &str) -> Option<&'static str> {
        match cpp_ty {
            "bool" => Some("BoolDeserializer"),
            "int8_t" => Some("I8Deserializer"),
            "int16_t" => Some("I16Deserializer"),
            "int32_t" => Some("I32Deserializer"),
            "int64_t" => Some("I64Deserializer"),
            "__int128" => Some("I128Deserializer"),
            "ptrdiff_t" => Some("IsizeDeserializer"),
            "uint8_t" => Some("U8Deserializer"),
            "uint16_t" => Some("U16Deserializer"),
            "uint32_t" => Some("U32Deserializer"),
            "uint64_t" => Some("U64Deserializer"),
            "unsigned __int128" => Some("U128Deserializer"),
            "size_t" => Some("UsizeDeserializer"),
            "float" => Some("F32Deserializer"),
            "double" => Some("F64Deserializer"),
            "char32_t" => Some("CharDeserializer"),
            "rusty::String" => Some("StringDeserializer"),
            "rusty::Cow" => Some("CowStrDeserializer"),
            _ => None,
        }
    }

    fn try_emit_builtin_into_deserializer_ctor(
        &self,
        receiver_expr: &syn::Expr,
        receiver_cpp: &str,
        err_cpp: &str,
    ) -> Option<String> {
        let infer_path_binding_type = |expr: &syn::Expr| -> Option<syn::Type> {
            let path = match self.peel_paren_group_expr(expr) {
                syn::Expr::Path(path) => path,
                _ => return None,
            };
            if path.path.segments.len() != 1 {
                return None;
            }
            let local_name = path.path.segments[0].ident.to_string();
            self.lookup_local_binding_type(&local_name).or_else(|| {
                let struct_name = self.current_struct.as_ref()?;
                let field_ty = self.lookup_struct_field_type(struct_name, &local_name)?;
                self.expected_option_type_arg(Some(&field_ty))
                    .cloned()
                    .or(Some(field_ty))
            })
        };

        let recv_ty = self
            .infer_simple_expr_type(receiver_expr)
            .or_else(|| infer_path_binding_type(receiver_expr))
            .or_else(|| {
                let call = match self.peel_paren_group_expr(receiver_expr) {
                    syn::Expr::Call(call) => call,
                    _ => return None,
                };
                let func_path = match self.peel_paren_group_expr(call.func.as_ref()) {
                    syn::Expr::Path(path_expr) => &path_expr.path,
                    _ => return None,
                };
                let is_std_move = func_path
                    .segments
                    .last()
                    .is_some_and(|seg| seg.ident == "move");
                if !is_std_move || call.args.len() != 1 {
                    return None;
                }
                let arg = call.args.first()?;
                self.infer_simple_expr_type(arg)
                    .or_else(|| infer_path_binding_type(arg))
            })?;
        let recv_ty = self.peel_reference_paren_group_type(&recv_ty);
        let recv_cpp = Self::strip_cpp_cvref_qualifiers(self.map_type(recv_ty));
        let owner = self.builtin_deserializer_owner_for_cpp_type(recv_cpp.as_str())?;
        Some(format!(
            "::de::value::{}<{}>::new_({})",
            owner, err_cpp, receiver_cpp
        ))
    }

    fn type_contains_unresolved_self_type_path(&self, ty: &syn::Type) -> bool {
        match ty {
            syn::Type::Path(tp) => {
                if tp.qself.is_none()
                    && tp.path.segments.len() == 1
                    && tp.path.segments[0].ident == "Self"
                    && self.current_struct.is_none()
                {
                    return true;
                }
                if let Some(qself) = tp.qself.as_ref()
                    && self.type_contains_unresolved_self_type_path(&qself.ty)
                {
                    return true;
                }
                tp.path.segments.iter().any(|seg| match &seg.arguments {
                    syn::PathArguments::AngleBracketed(args) => {
                        args.args.iter().any(|arg| match arg {
                            syn::GenericArgument::Type(inner) => {
                                self.type_contains_unresolved_self_type_path(inner)
                            }
                            _ => false,
                        })
                    }
                    syn::PathArguments::Parenthesized(args) => {
                        args.inputs
                            .iter()
                            .any(|inner| self.type_contains_unresolved_self_type_path(inner))
                            || match &args.output {
                                syn::ReturnType::Type(_, ty) => {
                                    self.type_contains_unresolved_self_type_path(ty)
                                }
                                syn::ReturnType::Default => false,
                            }
                    }
                    syn::PathArguments::None => false,
                })
            }
            syn::Type::Reference(r) => self.type_contains_unresolved_self_type_path(&r.elem),
            syn::Type::Ptr(p) => self.type_contains_unresolved_self_type_path(&p.elem),
            syn::Type::Paren(p) => self.type_contains_unresolved_self_type_path(&p.elem),
            syn::Type::Group(g) => self.type_contains_unresolved_self_type_path(&g.elem),
            syn::Type::Tuple(t) => t
                .elems
                .iter()
                .any(|elem| self.type_contains_unresolved_self_type_path(elem)),
            syn::Type::Array(a) => self.type_contains_unresolved_self_type_path(&a.elem),
            syn::Type::Slice(s) => self.type_contains_unresolved_self_type_path(&s.elem),
            syn::Type::ImplTrait(it) => it.bounds.iter().any(|bound| match bound {
                syn::TypeParamBound::Trait(tb) => {
                    if tb.path.segments.iter().any(|seg| {
                        self.type_contains_unresolved_self_type_path(&syn::Type::Path(
                            syn::TypePath {
                                qself: None,
                                path: syn::Path::from(seg.ident.clone()),
                            },
                        ))
                    }) {
                        return true;
                    }
                    tb.path.segments.iter().any(|seg| match &seg.arguments {
                        syn::PathArguments::AngleBracketed(args) => {
                            args.args.iter().any(|arg| match arg {
                                syn::GenericArgument::Type(inner) => {
                                    self.type_contains_unresolved_self_type_path(inner)
                                }
                                _ => false,
                            })
                        }
                        syn::PathArguments::Parenthesized(args) => {
                            args.inputs
                                .iter()
                                .any(|inner| self.type_contains_unresolved_self_type_path(inner))
                                || match &args.output {
                                    syn::ReturnType::Type(_, ty) => {
                                        self.type_contains_unresolved_self_type_path(ty)
                                    }
                                    syn::ReturnType::Default => false,
                                }
                        }
                        syn::PathArguments::None => false,
                    })
                }
                _ => false,
            }),
            syn::Type::TraitObject(obj) => obj.bounds.iter().any(|bound| match bound {
                syn::TypeParamBound::Trait(tb) => tb.path.segments.iter().any(|seg| {
                    if self.type_contains_unresolved_self_type_path(&syn::Type::Path(
                        syn::TypePath {
                            qself: None,
                            path: syn::Path::from(seg.ident.clone()),
                        },
                    )) {
                        return true;
                    }
                    match &seg.arguments {
                        syn::PathArguments::AngleBracketed(args) => {
                            args.args.iter().any(|arg| match arg {
                                syn::GenericArgument::Type(inner) => {
                                    self.type_contains_unresolved_self_type_path(inner)
                                }
                                _ => false,
                            })
                        }
                        syn::PathArguments::Parenthesized(args) => {
                            args.inputs
                                .iter()
                                .any(|inner| self.type_contains_unresolved_self_type_path(inner))
                                || match &args.output {
                                    syn::ReturnType::Type(_, ty) => {
                                        self.type_contains_unresolved_self_type_path(ty)
                                    }
                                    syn::ReturnType::Default => false,
                                }
                        }
                        syn::PathArguments::None => false,
                    }
                }),
                _ => false,
            }),
            _ => false,
        }
    }

    fn type_contains_unresolved_placeholder_like(&self, ty: &syn::Type) -> bool {
        self.type_contains_infer(ty)
            || self.type_contains_in_scope_type_param(ty)
            || self.type_contains_unresolved_self_type_path(ty)
    }

    fn type_is_concrete_hint_candidate(&self, ty: &syn::Type) -> bool {
        !self.type_contains_infer(ty)
            && !self.type_contains_in_scope_type_param(ty)
            && !self.type_contains_unbound_single_letter_generic(ty)
            && !self.type_contains_unresolved_placeholder_like(ty)
            && !self.type_contains_single_segment_local_binding_type_path(ty)
    }

    fn type_is_placeholder_hint_candidate_allow_scoped_generics(&self, ty: &syn::Type) -> bool {
        !self.type_contains_infer(ty)
            && !self.type_contains_unbound_single_letter_generic(ty)
            && !self.type_contains_unresolved_self_type_path(ty)
            && !self.type_maps_to_auto_placeholder_like(ty)
            && !self.type_contains_single_segment_local_binding_type_path(ty)
    }

    fn type_contains_single_segment_local_binding_type_path(&self, ty: &syn::Type) -> bool {
        match self.peel_reference_paren_group_type(ty) {
            syn::Type::Path(tp) => {
                if tp.qself.is_none()
                    && tp.path.segments.len() == 1
                    && let Some(seg) = tp.path.segments.first()
                    && matches!(seg.arguments, syn::PathArguments::None)
                {
                    let ident = seg.ident.to_string();
                    let lower_unresolved = ident
                        .chars()
                        .next()
                        .is_some_and(|ch| ch.is_ascii_lowercase())
                        && types::map_primitive_type(&ident).is_none()
                        && types::map_std_type(&ident).is_none()
                        && !self.is_local_type_name_in_scope(&ident)
                        && !self.local_declared_types.contains(&ident);
                    if self.is_local_binding_in_scope(&ident) || lower_unresolved {
                        return true;
                    }
                }
                tp.path.segments.iter().any(|seg| match &seg.arguments {
                    syn::PathArguments::AngleBracketed(args) => {
                        args.args.iter().any(|arg| match arg {
                            syn::GenericArgument::Type(inner) => {
                                self.type_contains_single_segment_local_binding_type_path(inner)
                            }
                            _ => false,
                        })
                    }
                    syn::PathArguments::Parenthesized(args) => {
                        args.inputs.iter().any(|inner| {
                            self.type_contains_single_segment_local_binding_type_path(inner)
                        }) || match &args.output {
                            syn::ReturnType::Type(_, output) => {
                                self.type_contains_single_segment_local_binding_type_path(output)
                            }
                            syn::ReturnType::Default => false,
                        }
                    }
                    syn::PathArguments::None => false,
                })
            }
            syn::Type::Reference(r) => {
                self.type_contains_single_segment_local_binding_type_path(&r.elem)
            }
            syn::Type::Ptr(p) => self.type_contains_single_segment_local_binding_type_path(&p.elem),
            syn::Type::Paren(p) => {
                self.type_contains_single_segment_local_binding_type_path(&p.elem)
            }
            syn::Type::Group(g) => {
                self.type_contains_single_segment_local_binding_type_path(&g.elem)
            }
            syn::Type::Tuple(t) => t
                .elems
                .iter()
                .any(|elem| self.type_contains_single_segment_local_binding_type_path(elem)),
            syn::Type::Array(a) => {
                self.type_contains_single_segment_local_binding_type_path(&a.elem)
            }
            syn::Type::Slice(s) => {
                self.type_contains_single_segment_local_binding_type_path(&s.elem)
            }
            _ => false,
        }
    }

    fn type_maps_to_auto_placeholder_like(&self, ty: &syn::Type) -> bool {
        let mapped = self.map_type(ty);
        mapped.contains("/* TODO") || type_string_has_auto_placeholder(&mapped)
    }

    fn type_maps_to_branch_local_decltype(&self, ty: &syn::Type) -> bool {
        self.map_type(ty).contains("decltype((std::move(")
    }



    fn expected_option_type_arg<'a>(
        &self,
        expected_ty: Option<&'a syn::Type>,
    ) -> Option<&'a syn::Type> {
        let ty = expected_ty?;
        match ty {
            syn::Type::Path(tp) => {
                let last = tp.path.segments.last()?;
                let last_ident = last.ident.to_string();
                if last.ident != "Option" && !self.option_type_aliases.contains(&last_ident) {
                    return None;
                }
                let syn::PathArguments::AngleBracketed(args) = &last.arguments else {
                    return None;
                };
                args.args.iter().find_map(|arg| match arg {
                    syn::GenericArgument::Type(t) => Some(t),
                    _ => None,
                })
            }
            syn::Type::Reference(r) => self.expected_option_type_arg(Some(&r.elem)),
            syn::Type::Paren(p) => self.expected_option_type_arg(Some(&p.elem)),
            syn::Type::Group(g) => self.expected_option_type_arg(Some(&g.elem)),
            _ => None,
        }
    }

    fn option_inner_needs_typed_make_optional(&self, inner_ty: &syn::Type) -> bool {
        if self.should_soften_dependent_assoc_mode()
            && (self.type_contains_dependent_assoc(inner_ty)
                || self.type_references_current_struct_assoc(inner_ty))
        {
            return false;
        }
        match inner_ty {
            syn::Type::Path(tp) => {
                if tp.qself.is_some() {
                    return true;
                }
                if tp.path.segments.len() >= 2 {
                    if let Some(first) = tp.path.segments.first() {
                        return first
                            .ident
                            .to_string()
                            .chars()
                            .next()
                            .is_some_and(|c| c.is_ascii_uppercase());
                    }
                }
                false
            }
            syn::Type::Reference(r) => self.option_inner_needs_typed_make_optional(&r.elem),
            syn::Type::Paren(p) => self.option_inner_needs_typed_make_optional(&p.elem),
            syn::Type::Group(g) => self.option_inner_needs_typed_make_optional(&g.elem),
            _ => false,
        }
    }

    fn expected_type_generic_args(&self, expected_ty: &syn::Type) -> Option<Vec<String>> {
        match expected_ty {
            syn::Type::Path(tp) => {
                let last = tp.path.segments.last()?;
                let syn::PathArguments::AngleBracketed(args) = &last.arguments else {
                    return None;
                };
                let mapped: Vec<String> = args
                    .args
                    .iter()
                    .filter_map(|arg| match arg {
                        syn::GenericArgument::Type(t) => Some(self.map_type(t)),
                        syn::GenericArgument::Const(c) => Some(self.emit_expr_to_string(c)),
                        _ => None,
                    })
                    .collect();
                if mapped.is_empty() {
                    None
                } else {
                    Some(mapped)
                }
            }
            syn::Type::Reference(r) => self.expected_type_generic_args(&r.elem),
            syn::Type::Paren(p) => self.expected_type_generic_args(&p.elem),
            syn::Type::Group(g) => self.expected_type_generic_args(&g.elem),
            _ => None,
        }
    }

    fn expected_type_generic_args_for_owner(
        &self,
        expected_ty: &syn::Type,
        owner_name: &str,
    ) -> Option<Vec<String>> {
        match expected_ty {
            syn::Type::Path(tp) => {
                let last = tp.path.segments.last()?;
                let expected_owner = last.ident.to_string();
                if expected_owner != owner_name
                    && !(owner_name == "Self"
                        && self
                            .current_struct
                            .as_deref()
                            .is_some_and(|current| current == expected_owner))
                {
                    return None;
                }
                let syn::PathArguments::AngleBracketed(args) = &last.arguments else {
                    return None;
                };
                let mapped: Vec<String> = args
                    .args
                    .iter()
                    .filter_map(|arg| match arg {
                        syn::GenericArgument::Type(t) => Some(self.map_type(t)),
                        syn::GenericArgument::Const(c) => Some(self.emit_expr_to_string(c)),
                        _ => None,
                    })
                    .collect();
                if mapped.is_empty() {
                    None
                } else {
                    Some(mapped)
                }
            }
            syn::Type::Reference(r) => {
                self.expected_type_generic_args_for_owner(&r.elem, owner_name)
            }
            syn::Type::Paren(p) => self.expected_type_generic_args_for_owner(&p.elem, owner_name),
            syn::Type::Group(g) => self.expected_type_generic_args_for_owner(&g.elem, owner_name),
            _ => None,
        }
    }

    fn type_is_bare_generic_param_like(&self, ty: &syn::Type) -> bool {
        let ty = self.peel_reference_paren_group_type(ty);
        let syn::Type::Path(tp) = ty else {
            return false;
        };
        if tp.qself.is_some() || tp.path.segments.len() != 1 {
            return false;
        }
        let ident = tp.path.segments[0].ident.to_string();
        if self.is_type_param_in_scope(&ident) || self.is_struct_type_param(&ident) {
            return true;
        }
        if self.is_local_type_name_in_scope(&ident)
            || self.local_declared_types.contains(&ident)
            || self.declared_item_names.contains(&ident)
            || types::map_primitive_type(&ident).is_some()
        {
            return false;
        }
        let mut has_alpha = false;
        ident.chars().all(|c| {
            if c.is_ascii_alphabetic() {
                has_alpha = true;
                c.is_ascii_uppercase()
            } else {
                c.is_ascii_digit() || c == '_'
            }
        }) && has_alpha
    }

    /// Returns true if `ty` looks like a type parameter (e.g., `T`, `F`, `E`).
    /// These are single-segment paths with an uppercase-first-identifier — Rust's
    /// convention for type parameter names. Type parameters are not valid C++
    /// template arguments, so we skip them and fall through to decltype inference.
    fn is_type_parameter(ty: &syn::Type) -> bool {
        match ty {
            syn::Type::Path(tp) => {
                tp.qself.is_none()
                    && tp.path.segments.len() == 1
                    && tp.path.segments[0]
                        .ident
                        .to_string()
                        .chars()
                        .next()
                        .is_some_and(|c| c.is_ascii_uppercase())
            }
            syn::Type::Reference(r) => Self::is_type_parameter(&r.elem),
            syn::Type::Paren(p) => Self::is_type_parameter(&p.elem),
            syn::Type::Group(g) => Self::is_type_parameter(&g.elem),
            _ => false,
        }
    }




    fn expected_vec_element_type<'a>(
        &self,
        expected_ty: Option<&'a syn::Type>,
    ) -> Option<&'a syn::Type> {
        let ty = expected_ty?;
        match ty {
            syn::Type::Path(tp) => {
                let last = tp.path.segments.last()?;
                if last.ident != "Vec" {
                    return None;
                }
                let syn::PathArguments::AngleBracketed(args) = &last.arguments else {
                    return None;
                };
                args.args.iter().find_map(|arg| match arg {
                    syn::GenericArgument::Type(t) => Some(t),
                    _ => None,
                })
            }
            syn::Type::Reference(r) => self.expected_vec_element_type(Some(r.elem.as_ref())),
            syn::Type::Paren(p) => self.expected_vec_element_type(Some(p.elem.as_ref())),
            syn::Type::Group(g) => self.expected_vec_element_type(Some(g.elem.as_ref())),
            _ => None,
        }
    }

    fn expected_path_type_arg_by_last_ident<'a>(
        &self,
        expected_ty: &'a syn::Type,
        last_ident: &str,
        arg_idx: usize,
    ) -> Option<&'a syn::Type> {
        let ty = self.peel_reference_paren_group_type(expected_ty);
        let syn::Type::Path(tp) = ty else {
            return None;
        };
        let last = tp.path.segments.last()?;
        if last.ident != last_ident {
            return None;
        }
        let syn::PathArguments::AngleBracketed(args) = &last.arguments else {
            return None;
        };
        args.args
            .iter()
            .filter_map(|arg| match arg {
                syn::GenericArgument::Type(ty) => Some(ty),
                _ => None,
            })
            .nth(arg_idx)
    }

    fn try_emit_boxed_u8_array_expr(&self, expr: &syn::Expr) -> Option<String> {
        let peeled = self.peel_paren_group_expr(expr);
        match peeled {
            syn::Expr::Unary(unary) if matches!(unary.op, syn::UnOp::Deref(_)) => {
                if let syn::Expr::Lit(syn::ExprLit {
                    lit: syn::Lit::ByteStr(bs),
                    ..
                }) = self.peel_paren_group_expr(&unary.expr)
                {
                    let bytes = bs.value();
                    if bytes.is_empty() {
                        return Some("std::array<uint8_t, 0>{}".to_string());
                    }
                    let elems: Vec<String> = bytes
                        .iter()
                        .map(|b| format!("static_cast<uint8_t>({})", b))
                        .collect();
                    return Some(format!("std::array{{{}}}", elems.join(", ")));
                }
                None
            }
            syn::Expr::Array(arr) => {
                if arr.elems.is_empty() {
                    return Some("std::array<uint8_t, 0>{}".to_string());
                }
                let elems: Vec<String> = arr
                    .elems
                    .iter()
                    .map(|elem| format!("static_cast<uint8_t>({})", self.emit_expr_to_string(elem)))
                    .collect();
                Some(format!("std::array{{{}}}", elems.join(", ")))
            }
            syn::Expr::Repeat(repeat) => {
                let value = self.emit_expr_to_string(&repeat.expr);
                let len = self.emit_expr_to_string(&repeat.len);
                Some(format!(
                    "rusty::array_repeat(static_cast<uint8_t>({}), {})",
                    value, len
                ))
            }
            _ => None,
        }
    }

    fn try_emit_boxed_array_expr_with_expected_elem_type(
        &self,
        expr: &syn::Expr,
        expected_elem_ty: &syn::Type,
    ) -> Option<String> {
        let peeled = self.peel_paren_group_expr(expr);
        match peeled {
            syn::Expr::Array(arr) => {
                if arr.elems.is_empty() {
                    let elem_cpp = self.map_type(expected_elem_ty);
                    return Some(format!("std::array<{}, 0>{{}}", elem_cpp));
                }
                let elems: Vec<String> = arr
                    .elems
                    .iter()
                    .map(|elem| {
                        self.emit_expr_to_string_with_expected(elem, Some(expected_elem_ty))
                    })
                    .collect();
                Some(format!("std::array{{{}}}", elems.join(", ")))
            }
            syn::Expr::Repeat(repeat) => {
                let value =
                    self.emit_expr_to_string_with_expected(&repeat.expr, Some(expected_elem_ty));
                let len = self.emit_expr_to_string(&repeat.len);
                Some(format!("rusty::array_repeat({}, {})", value, len))
            }
            _ => None,
        }
    }

    fn emit_tuple_expr_with_expected_shape(
        &self,
        tuple_expr: &syn::ExprTuple,
        expected_tuple_ty: &syn::TypeTuple,
    ) -> Option<String> {
        if tuple_expr.elems.len() != expected_tuple_ty.elems.len() {
            return None;
        }
        let elems: Vec<String> = tuple_expr
            .elems
            .iter()
            .enumerate()
            .map(|(idx, elem)| {
                self.emit_tuple_element_with_expected_type(
                    elem,
                    expected_tuple_ty.elems.iter().nth(idx),
                )
            })
            .collect();
        let expected_tuple_cpp = self.map_type(&syn::Type::Tuple(expected_tuple_ty.clone()));
        Some(format!("{}{{{}}}", expected_tuple_cpp, elems.join(", ")))
    }

