fn rewrite_std_ops_import(path: &str) -> Option<UseImportAction> {
    if matches!(path, "std::ops" | "core::ops") {
        return Some(UseImportAction::RustOnly);
    }
    // `std::ops::Bound` is an enum (Included/Excluded/Unbounded) with a
    // rusty mirror at `rusty::Bound`. The rest of `std::ops::*` is
    // operator/range traits that have no direct C++ equivalent — keep
    // emitting those as `RustOnly` comments.
    if matches!(path, "std::ops::Bound" | "core::ops::Bound") {
        return Some(UseImportAction::Using("rusty::Bound".to_string()));
    }
    if path.starts_with("std::ops::") || path.starts_with("core::ops::") {
        return Some(UseImportAction::RustOnly);
    }
    None
}

