fn rewrite_std_marker_import(path: &str) -> Option<UseImportAction> {
    if path == "std::marker::PhantomData" {
        return Some(UseImportAction::Using("rusty::PhantomData".to_string()));
    }
    // `use std::marker;` brings the module into scope so later
    // references like `marker::PhantomData<T>` can resolve. Emit a
    // namespace alias so the C++ lookup works without rewriting
    // every reference at the use site (PhantomData lives at
    // `rusty::PhantomData`, so `marker::PhantomData` ≡ `rusty::PhantomData`
    // works as long as `namespace marker = rusty;` is in scope).
    if path == "std::marker" {
        return Some(UseImportAction::Raw("namespace marker = rusty;".to_string()));
    }
    None
}

